#!/usr/bin/env node

/**
 * generate-kanban-data.js — build the KanbanBoard data from blog-post frontmatter.
 *
 * Mirrors generate-ideas-data.js / generate-changelog-data.js: scan the blog posts,
 * read each post's frontmatter, and emit a JSON the <KanbanBoard> component consumes.
 * A card is generated PER POST (never hand-authored), so the board can never drift from
 * the posts it indexes — moving a card = changing a post's `stage` frontmatter.
 *
 * OUTPUT (gitignored, regenerated by `npm run generate-assets`; NEVER hand-edit — the
 * block-generated-edits hook refuses writes to it):
 *   src/components/KanbanBoard/kanban-data.json
 *
 * SHAPE: { "<boardId>": [ {slug, title, summary, permalink, stage, priority, kind, date} ] }
 * The component slots each card into a column by its `stage` (see BOARDS below for the
 * kind→board mapping and each board's columns). A post with no recognized stage for its
 * board falls into that board's first column.
 *
 * BOARDS (the board-aware contract — kept in lockstep with the idea-grooming skill +
 * the experiment-lifecycle skills, which know which kind belongs to which board and how
 * advancing a card maps to a `stage` frontmatter change):
 *   - experiments: cards = experiment posts (kind experiment-plan 📝 / experiment-result 📊).
 *       columns by stage: proposed | designed | running | analyzing | concluded.
 *       A kind=experiment-result post is always shown in the terminal (concluded) column.
 *   - ideas: cards = idea/initiative posts (kind reflection/design-story/etc. tagged as
 *       an initiative via `board: ideas` frontmatter). columns by stage:
 *       backlog | exploring | building | shipped.
 *
 * A post opts INTO a board either by its `kind` (experiments) or by an explicit
 * `board: <id>` frontmatter (ideas) — so a post is never on a board by accident.
 */

const fs = require('fs');
const path = require('path');
const matter = require('gray-matter');

const ROOT = path.join(__dirname, '..');
// The board cards come from TWO blog instances now: experiment posts live on /initiatives
// (blog/), and idea posts (board: ideas) live on /thoughts (the Thoughts & Ideas instance —
// UNACTIONED ideas). Each source carries its own permalink base so a card links to the right
// instance. (An experiment post is never in /thoughts and an idea post can be in either, by its
// `board: ideas` frontmatter; the de-dup in build() handles a post that somehow matches both.)
const SOURCES = [
  {dir: path.join(ROOT, 'blog'), base: '/initiatives'},
  {dir: path.join(ROOT, 'thoughts'), base: '/thoughts'},
];
const outputFile = path.join(ROOT, 'src', 'components', 'KanbanBoard', 'kanban-data.json');

// Board definitions: each board's ordered columns + how a post qualifies for it.
// `kinds` = post kinds that auto-belong to this board. `columns` = ordered stage ids.
// `terminalKind` (optional) = a kind that always lands in the LAST column regardless of stage.
const BOARDS = {
  experiments: {
    kinds: ['experiment-plan', 'experiment-result'],
    columns: ['proposed', 'designed', 'running', 'analyzing', 'concluded'],
    terminalKind: 'experiment-result', // a result post is, by definition, concluded
  },
  ideas: {
    // Ideas opt in explicitly via `board: ideas` (any kind), since an idea post can be a
    // reflection/design-story/etc. The kind list is empty → only explicit opt-in counts.
    kinds: [],
    columns: ['backlog', 'exploring', 'building', 'shipped'],
  },
  research: {
    // Research posts (kind: research 🔬 — things I want to investigate before deciding) auto-belong;
    // any post can also opt in with `board: research`. Lifecycle: want-to → investigating → done.
    kinds: ['research'],
    columns: ['backlog', 'researching', 'learned'],
  },
};

// Map a post's `stage` frontmatter to a board column. Accepts a few synonyms so authors
// aren't forced to memorize exact column ids; an unrecognized stage → first column.
const STAGE_SYNONYMS = {
  // experiments
  draft: 'designed',
  design: 'designed',
  designing: 'designed',
  live: 'running',
  run: 'running',
  analyze: 'analyzing',
  analysis: 'analyzing',
  done: 'concluded',
  complete: 'concluded',
  concluded: 'concluded',
  'rolled-out': 'concluded',
  abandoned: 'concluded',
  // ideas
  idea: 'backlog',
  todo: 'backlog',
  explore: 'exploring',
  build: 'building',
  wip: 'building',
  ship: 'shipped',
  shipped: 'shipped',
  // research (backlog → researching → learned). `backlog` is shared with ideas; the columns
  // researching/learned match directly. Friendly synonyms that don't collide with the above:
  investigating: 'researching',
  researching: 'researching',
  learn: 'learned',
  learnt: 'learned',
  learned: 'learned',
};

function resolveColumn(board, stageRaw, kind) {
  const def = BOARDS[board];
  if (def.terminalKind && kind === def.terminalKind) {
    return def.columns[def.columns.length - 1];
  }
  const stage = (stageRaw || '').toString().trim().toLowerCase();
  if (def.columns.includes(stage)) return stage;
  const syn = STAGE_SYNONYMS[stage];
  if (syn && def.columns.includes(syn)) return syn;
  return def.columns[0]; // unknown/empty stage → first column
}

// Blog permalink: base is the source instance's routeBasePath (/initiatives or /thoughts;
// see docusaurus.config blog routeBasePath). A post's slug is its frontmatter `slug` or the
// de-dated filename.
function permalinkFor(base, fileSlug, fm) {
  const slug = (fm.slug || fileSlug).toString().replace(/^\//, '');
  return `${base}/${slug}`;
}

// gray-matter parses a YAML `date: 2026-05-31` into a JS Date. Normalize any date value
// to a stable YYYY-MM-DD string so the JSON is deterministic (a verbose Date.toString()
// would also churn the gitignored output and sort oddly).
function isoDate(value) {
  if (!value) return '';
  if (value instanceof Date && !isNaN(value)) return value.toISOString().slice(0, 10);
  const s = value.toString();
  const m = s.match(/\d{4}-\d{2}-\d{2}/);
  return m ? m[0] : s;
}

// Tags that describe a card's THEME drive the board's tag chips + filter. The post's raw
// `tags:` carry some structural noise that is true of EVERY card on the board (every Ideas
// card is an "idea"), so it would make a useless, always-on chip — drop those. What remains
// is the meaningful theme (scripting, automation, notes, backup, app, …).
const TAG_NOISE = new Set(['idea', 'ideas', 'thoughts', 'thought']);
function themeTags(value) {
  if (!Array.isArray(value)) return [];
  const seen = new Set();
  const out = [];
  for (const t of value) {
    const tag = (t == null ? '' : t.toString()).trim().toLowerCase();
    if (!tag || TAG_NOISE.has(tag) || seen.has(tag)) continue;
    seen.add(tag);
    out.push(tag);
  }
  return out;
}

function listPosts(dir) {
  if (!fs.existsSync(dir)) return [];
  return fs
    .readdirSync(dir, {withFileTypes: true})
    .filter((e) => e.isFile() && /\.mdx?$/.test(e.name) && !e.name.startsWith('_'))
    .map((e) => e.name);
}

function build() {
  const boards = Object.fromEntries(Object.keys(BOARDS).map((b) => [b, []]));

  for (const {dir, base} of SOURCES) {
    for (const name of listPosts(dir)) {
      const raw = fs.readFileSync(path.join(dir, name), 'utf-8');
      let fm;
      try {
        fm = matter(raw).data || {};
      } catch {
        continue; // unparseable frontmatter — other validators flag it
      }
      // Drafts are dev-only; the prod build excludes them, so a card linking to a draft
      // would 404 in prod. Skip drafts here so the board only ever cards published posts.
      if (fm.draft === true) continue;

      const fileSlug = name.replace(/\.(md|mdx)$/, '').replace(/^\d{4}-\d{2}-\d{2}-/, '');
      const kind = (fm.kind || '').toString();

      // Which board(s) does this post belong to?
      const targetBoards = [];
      for (const [boardId, def] of Object.entries(BOARDS)) {
        if (def.kinds.includes(kind)) targetBoards.push(boardId);
      }
      if (fm.board && boards[fm.board]) targetBoards.push(fm.board);

      for (const boardId of new Set(targetBoards)) {
        boards[boardId].push({
          slug: fm.slug ? fm.slug.toString().replace(/^\//, '') : fileSlug,
          title: (fm.title || fileSlug).toString().replace(/^['"]|['"]$/g, ''),
          summary: (fm.summary || fm.description || '').toString(),
          permalink: permalinkFor(base, fileSlug, fm),
          stage: resolveColumn(boardId, fm.stage, kind),
          priority: (fm.priority || 'medium').toString(),
          kind,
          // Optional CLASSIFICATION of the card (a `class:` frontmatter field, e.g. `first-time`).
          // A class groups a SUBSET of a board's cards by what kind of thing they are (e.g. the
          // "first-time / new things" ideas) without being a card itself. Rendered as a badge.
          class: fm.class ? fm.class.toString() : '',
          // THEME tags (the post's `tags:` minus the always-on noise) drive the board's tag
          // chips + filter bar — see themeTags() above and the KanbanBoard component.
          tags: themeTags(fm.tags),
          date: isoDate(fm.date),
        });
      }
    }
  }

  // Newest first within each board (stable, matches the changelog/ideas convention).
  for (const list of Object.values(boards)) {
    list.sort((a, b) => (b.date || '').localeCompare(a.date || ''));
  }
  return boards;
}

const boards = build();
const outputDir = path.dirname(outputFile);
if (!fs.existsSync(outputDir)) fs.mkdirSync(outputDir, {recursive: true});
fs.writeFileSync(outputFile, JSON.stringify(boards, null, 2), 'utf-8');

const counts = Object.entries(boards)
  .map(([b, l]) => `${b}=${l.length}`)
  .join(', ');
console.log(`Generated kanban data: ${counts} -> ${path.relative(ROOT, outputFile)}`);
